namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string CourseCode { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, ErrorMessage = "Name cannot exceed 100 characters.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and fundamental forces." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and communication." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS101", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00-9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory programming and has authored two textbooks on Python.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", CourseCode = "CS201", Description = "Advanced data structures including trees, graphs, and hash tables. Algorithm design and complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30 AM-12:00 PM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published extensively in ACM journals.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", CourseCode = "CS305", Description = "Relational database design, SQL, normalization, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00-3:15 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked as a database architect at Oracle for 10 years before joining academia.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", CourseCode = "MATH101", Description = "Limits, derivatives, and integrals of single-variable functions.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00-10:50 AM", InstructorName = "Dr. Robert Taylor", InstructorBio = "Dr. Taylor is an award-winning educator with a passion for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH202", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00-2:15 PM", InstructorName = "Dr. Emily Zhang", InstructorBio = "Dr. Zhang's research focuses on applied linear algebra in machine learning.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Statistics", CourseCode = "MATH301", Description = "Probability theory, statistical inference, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00-11:50 AM", InstructorName = "Dr. Alan Kumar", InstructorBio = "Dr. Kumar brings real-world data analysis experience from his work with the Census Bureau.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Title = "Classical Mechanics", CourseCode = "PHYS101", Description = "Newton's laws, energy, momentum, rotational dynamics, and oscillations.", Credits = 4, Schedule = "Tue/Thu 9:00-10:15 AM", InstructorName = "Dr. Michael Brown", InstructorBio = "Dr. Brown is a former NASA researcher specializing in orbital mechanics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Title = "Electromagnetism", CourseCode = "PHYS202", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00-1:50 PM", InstructorName = "Dr. Lisa Wang", InstructorBio = "Dr. Wang's research in superconductors has been published in Nature Physics.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Title = "Creative Writing", CourseCode = "ENG201", Description = "Workshop-based course covering fiction, poetry, and creative nonfiction.", Credits = 3, Schedule = "Tue/Thu 3:00-4:15 PM", InstructorName = "Prof. David Miller", InstructorBio = "Prof. Miller is a published novelist and recipient of the PEN/Faulkner Award.", DepartmentId = 4, DepartmentName = "English", IsFeatured = true },
            new() { Id = 10, Title = "American Literature", CourseCode = "ENG301", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "Mon/Wed 10:00-11:15 AM", InstructorName = "Dr. Patricia Green", InstructorBio = "Dr. Green specializes in 20th-century American fiction and African American literature.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 11, Title = "World History to 1500", CourseCode = "HIST101", Description = "Survey of world civilizations from antiquity through the medieval period.", Credits = 3, Schedule = "Tue/Thu 11:00 AM-12:15 PM", InstructorName = "Dr. Thomas Reed", InstructorBio = "Dr. Reed has led archaeological expeditions in the Mediterranean and Middle East.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
            new() { Id = 12, Title = "Modern European History", CourseCode = "HIST301", Description = "Europe from the Enlightenment through the Cold War, covering political and cultural transformations.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00-2:50 PM", InstructorName = "Dr. Anna Schmidt", InstructorBio = "Dr. Schmidt is a specialist in 20th-century European political history with a focus on Germany.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In production, this would persist to a database
        return request.CourseId > 0
            && !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId);
    }
}

