    @if (courses.Any())
    {
        <div class="course-list">
            @foreach (var course in courses)
            {
                <div class="course-item">
                    <div class="course-item-header">
                        <span class="badge">@course.CourseCode</span>
                        <h3>@course.Title</h3>
                    </div>
                    <div class="course-item-details">
                        <span>@course.DepartmentName</span>
                        <span>@course.Credits credits</span>
                        <span>@course.Schedule</span>
                        <span>@course.InstructorName</span>
                    </div>
                    <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            }
        </div>
    }
    else
    {
        <p class="no-results">No courses found matching your criteria.</p>
    }
</div>

@code {
    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private string searchTerm = string.Empty;
    private int selectedDepartmentId;
    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
            selectedDepartmentId = DepartmentId.Value;
        LoadCourses();
    }

    private int _previousDepartmentId;
    private string _previousSearchTerm = string.Empty;

    protected override void OnAfterRender(bool firstRender)
    {
        if (_previousDepartmentId != selectedDepartmentId || _previousSearchTerm != searchTerm)
        {
            _previousDepartmentId = selectedDepartmentId;
            _previousSearchTerm = searchTerm;
            LoadCourses();
            StateHasChanged();
        }
    }

    private void LoadCourses()
    {
        int? deptFilter = selectedDepartmentId > 0 ? selectedDepartmentId : null;
        courses = CatalogService.GetCourses(searchTerm, deptFilter);
    }
}

