@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<div class="container">
    <h1>Enrollment Request</h1>
    <p>Submit a request to enroll in a course. You will receive confirmation via your university email.</p>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h2>Request Submitted</h2>
            <p>Your enrollment request for <strong>@selectedCourseName</strong> has been received. You will be notified of your enrollment status.</p>
            <a href="/courses" class="btn btn-primary">Browse More Courses</a>
        </div>
    }
    else
    {
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="enrollment-form">
            <DataAnnotationsValidator />
            <ValidationSummary class="validation-summary" />

            <div class="form-group">
                <label for="studentName">Full Name</label>
                <InputText id="studentName" @bind-Value="model.StudentName" class="form-control" />
                <ValidationMessage For="() => model.StudentName" class="validation-message" />
            </div>

            <div class="form-group">
                <label for="studentId">Student ID</label>
                <InputText id="studentId" @bind-Value="model.StudentId" class="form-control" placeholder="e.g., STU12345" />
                <ValidationMessage For="() => model.StudentId" class="validation-message" />
            </div>

            <div class="form-group">
                <label for="courseId">Course</label>
                <InputSelect id="courseId" @bind-Value="model.CourseId" class="form-control">
                    <option value="0">-- Select a course --</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.CourseCode - @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" class="validation-message" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    [SupplyParameterFromForm]
    private EnrollmentRequest model { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && model.CourseId == 0)
            model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(model.CourseId);
        selectedCourseName = course != null ? $"{course.CourseCode} - {course.Title}" : "Unknown Course";

        if (CatalogService.SubmitEnrollmentRequest(model))
        {
            submitted = true;
        }
    }
}

