arguments.new_str:
/* Base styles */
:root {
    --primary: #1b4d8e;
    --primary-dark: #143a6b;
    --secondary: #2c7a4b;
    --accent: #e8a838;
    --text: #333;
    --text-light: #666;
    --bg: #f8f9fa;
    --white: #fff;
    --border: #dee2e6;
    --radius: 8px;
    --shadow: 0 2px 8px rgba(0,0,0,0.1);
}

*, *::before, *::after {
    box-sizing: border-box;
}

html, body {
    font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
    margin: 0;
    padding: 0;
    color: var(--text);
    background: var(--bg);
    line-height: 1.6;
}

/* Header */
.site-header {
    background: var(--primary);
    color: var(--white);
    padding: 0 2rem;
    box-shadow: var(--shadow);
    position: sticky;
    top: 0;
    z-index: 100;
}

.header-content {
    max-width: 1200px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 64px;
}

.site-logo {
    color: var(--white);
    text-decoration: none;
    font-size: 1.25rem;
    font-weight: 700;
}

.site-nav a {
    color: rgba(255,255,255,0.9);
    text-decoration: none;
    margin-left: 2rem;
    font-weight: 500;
    transition: color 0.2s;
}

.site-nav a:hover {
    color: var(--accent);
}

/* Main content */
.main-content {
    max-width: 1200px;
    margin: 0 auto;
    padding: 2rem;
    min-height: calc(100vh - 140px);
}

/* Footer */
.site-footer {
    background: var(--primary-dark);
    color: rgba(255,255,255,0.8);
    text-align: center;
    padding: 1.5rem;
}

/* Hero */
.hero {
    text-align: center;
    padding: 3rem 1rem;
    background: linear-gradient(135deg, var(--primary) 0%, var(--primary-dark) 100%);
    color: var(--white);
    border-radius: var(--radius);
    margin-bottom: 2rem;
}

.hero h1 {
    margin: 0 0 0.5rem;
    font-size: 2.5rem;
}

.lead {
    font-size: 1.2rem;
    opacity: 0.9;
    margin: 0;
}

/* Buttons */
.btn {
    display: inline-block;
    padding: 0.6rem 1.2rem;
    border-radius: var(--radius);
